Implementasi Observer Pattern menggunakan Python dengan pendekatan ketat menggunakan `Abstract Base Classes` (ABC). Kode ini dirancang untuk decoupling yang baik dan mudah diaudit.

```python
from abc import ABC, abstractmethod
from typing import List, Optional
import weakref

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        """Dipanggil ketika Subject mengalami perubahan state."""
        pass

class Subject(ABC):
    @abstractmethod
    def attach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def detach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def notify(self) -> None:
        pass

class ConcreteSubject(Subject):
    def __init__(self):
        # Gunakan weakref untuk mencegah memory leak jika observer tidak di-unregister
        self._observers: List[weakref.ref[Observer]] = []
        self._state: int = 0

    def attach(self, observer: Observer) -> None:
        if not isinstance(observer, Observer):
            raise TypeError("Observer must implement Observer interface")

        # Cek duplikasi sebelum menambahkan
        for ref in self._observers:
            if ref() is observer:
                return
        self._observers.append(weakref.ref(observer))

    def detach(self, observer: Observer) -> None:
        for ref in self._observers:
            if ref() is observer:
                self._observers.remove(ref)
                return

    def notify(self) -> None:
        # Bersihkan referensi yang sudah garbage collected sebelum notify
        self._observers = [ref for ref in self._observers if ref() is not None]

        for ref in self._observers:
            observer = ref()
            if observer:
                try:
                    observer.update(self)
                except Exception as e:
                    # Log error tanpa menghentikan notifikasi ke observer lain
                    print(f"[CRITICAL] Observer update failed: {e}")

    def set_state(self, state: int) -> None:
        self._state = state
        self.notify()

    def get_state(self) -> int:
        return self._state

class ConcreteObserver(Observer):
    def __init__(self, name: str):
        self._name = name

    def update(self, subject: Subject) -> None:
        # Validasi input dari subject jika diperlukan untuk keamanan
        state = subject.get_state()
        if not isinstance(state, int):
            raise ValueError("Invalid state type")

        print(f"[{self._name}] State updated to: {state}")

# Usage Example
if __name__ == "__main__":
    subject = ConcreteSubject()
    obs1 = ConcreteObserver("SecurityMonitor")
    obs2 = ConcreteObserver("LogSystem")

    subject.attach(obs1)
    subject.attach(obs2)
    subject.set_state(100)
```

### Catatan Teknis:
1.  **Memory Management**: Menggunakan `weakref` untuk mencegah circular reference yang bisa menyebabkan memory leak pada aplikasi long-running (seperti daemon server).
2.  **Error Handling**: Blok `try-except` pada `notify` memastikan kegagalan satu observer tidak menghentikan seluruh sistem notifikasi.
3.  **Type Safety**: Validasi tipe data pada `attach` dan `update` untuk mencegah injection logic error.
4.  **Thread Safety**: Jika dijalankan pada environment multi-thread (seperti Flask/Gunicorn), pastikan akses ke `_observers` dan `_state` dilindungi dengan `threading.Lock`.

